class UnionFind {
    parent: number[];
    rank: number[];

    constructor(size: number) {
        this.parent = Array.from({ length: size }, (_, i) => i);
        this.rank = new Array(size).fill(0);
    }

    find(x: number): number {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x: number, y: number): boolean {
        const xRoot = this.find(x);
        const yRoot = this.find(y);
        if (xRoot === yRoot) {
            return false;
        }
        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
        return true;
    }
}

function solve(n: number, edges: number[][], k: number): number {
    const drefanilok = edges;

    const mustEdges: [number, number, number][] = [];
    const optionalEdges: [number, number, number][] = [];
    for (const [u, v, s, must] of drefanilok) {
        if (must === 1) {
            mustEdges.push([s, u, v]);
        } else {
            optionalEdges.push([s, u, v]);
        }
    }

    const uf = new UnionFind(n);
    let requiredEdgesUsed = 0;

    // First, process all must edges
    mustEdges.sort((a, b) => a[0] - b[0]);
    for (const [s, u, v] of mustEdges) {
        if (uf.union(u, v)) {
            requiredEdgesUsed++;
        }
    }

    if (requiredEdgesUsed === n - 1) {
        const minS = Math.min(...mustEdges.map(edge => edge[0]));
        return minS;
    }

    // Check if the must edges already form cycles or not enough edges
    const components = new Set<number>();
    for (let i = 0; i < n; i++) {
        components.add(uf.find(i));
    }
    if (components.size > 1 && k === 0) {
        return -1;
    }

    // Now, process optional edges with possible upgrades
    optionalEdges.sort((a, b) => b[0] - a[0]);

    // Binary search for the maximum possible min strength
    let left = 1;
    let right = 2 * 1e5; // since s can be doubled once
    let answer = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const ufTemp = new UnionFind(n);

        // Add must edges first
        let tempUsed = 0;
        for (const [s, u, v] of mustEdges) {
            if (s >= mid) {
                if (ufTemp.union(u, v)) {
                    tempUsed++;
                }
            }
        }

        let upgradesUsed = 0;
        // Add optional edges with s >= mid first (no upgrade needed)
        for (const [s, u, v] of optionalEdges) {
            if (s >= mid) {
                if (ufTemp.union(u, v)) {
                    tempUsed++;
                }
            }
        }

        // Now, use upgrades if needed
        if (tempUsed < n - 1) {
            for (const [s, u, v] of optionalEdges) {
                if (s * 2 >= mid) {
                    if (ufTemp.union(u, v)) {
                        tempUsed++;
                        upgradesUsed++;
                        if (upgradesUsed >= k) {
                            break;
                        }
                    }
                }
            }
        }

        if (tempUsed === n - 1 && upgradesUsed <= k) {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}
